import{_ as r,o as a,c as e,ak as l}from"./chunks/framework.C8uqSLax.js";const b=JSON.parse('{"title":"專案作品","description":"","frontmatter":{},"headers":[],"relativePath":"projects.md","filePath":"projects.md","lastUpdated":1781254545000}'),o={name:"projects.md"};function n(i,t,d,h,s,c){return a(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="專案作品" tabindex="-1">專案作品 <a class="header-anchor" href="#專案作品" aria-label="Permalink to “專案作品”">​</a></h1><div style="text-align:center;margin-bottom:2rem;"><h2 id="從-minecraft-伺服器到-erp-系統-從-android-app-到微電影" tabindex="-1">從 Minecraft 伺服器到 ERP 系統，從 Android App 到微電影 <a class="header-anchor" href="#從-minecraft-伺服器到-erp-系統-從-android-app-到微電影" aria-label="Permalink to “從 Minecraft 伺服器到 ERP 系統，從 Android App 到微電影”">​</a></h2><p>以下是我參與或創建的主要專案與作品。</p></div><hr><h2 id="東東的創世神伺服器" tabindex="-1">東東的創世神伺服器 <a class="header-anchor" href="#東東的創世神伺服器" aria-label="Permalink to “東東的創世神伺服器”">​</a></h2><h3 id="minecraft-遊戲伺服器" tabindex="-1">Minecraft 遊戲伺服器 <a class="header-anchor" href="#minecraft-遊戲伺服器" aria-label="Permalink to “Minecraft 遊戲伺服器”">​</a></h3><p>自 <strong>2013 年</strong>（Minecraft 1.5.2 時代）起創立並營運，是台灣少數持續經營超過十年的 Minecraft 伺服器之一。</p><h3 id="伺服器資訊" tabindex="-1">伺服器資訊 <a class="header-anchor" href="#伺服器資訊" aria-label="Permalink to “伺服器資訊”">​</a></h3><table tabindex="0"><thead><tr><th>項目</th><th>內容</th></tr></thead><tbody><tr><td><strong>伺服器名稱</strong></td><td>東東的創世神伺服器 (DDS)</td></tr><tr><td><strong>網站</strong></td><td><a href="https://wuc656.com" target="_blank" rel="noreferrer">wuc656.com</a></td></tr><tr><td><strong>主要版本</strong></td><td>1.12.2（也有 1.19.4 支援）</td></tr><tr><td><strong>遊戲模式</strong></td><td>插件生存</td></tr><tr><td><strong>特色系統</strong></td><td>Mcmmo 生活技能、住宅區、公會、寵物系統</td></tr><tr><td><strong>營運方式</strong></td><td>24 小時開服、0 Ban、無封鎖系統</td></tr><tr><td><strong>社群連結</strong></td><td><a href="https://discord.gg/VSeYAGN" target="_blank" rel="noreferrer">Discord</a> ｜ <a href="https://www.facebook.com/wud656/" target="_blank" rel="noreferrer">Facebook 粉絲團</a> ｜ <a href="https://www.facebook.com/groups/dongserver/" target="_blank" rel="noreferrer">Facebook 社團</a></td></tr></tbody></table><h3 id="伺服器特色" tabindex="-1">伺服器特色 <a class="header-anchor" href="#伺服器特色" aria-label="Permalink to “伺服器特色”">​</a></h3><ul><li><strong>Mcmmo 生活技能系統</strong>：玩家可以透過日常活動提升各項生活技能</li><li><strong>住宅區系統</strong>：玩家可以擁有專屬的住宅區域</li><li><strong>公會系統</strong>：支援玩家創建與管理公會</li><li><strong>寵物系統</strong>：玩家可以飼養與管理寵物</li><li><strong>優質玩家驗證制度</strong>：建立完善的玩家驗證機制</li><li><strong>新手友善環境</strong>：提供完善的教學與新手引導</li></ul><h3 id="伺服器歷史" tabindex="-1">伺服器歷史 <a class="header-anchor" href="#伺服器歷史" aria-label="Permalink to “伺服器歷史”">​</a></h3><ul><li><strong>2013 年</strong>：以 Minecraft 1.5.2 版本創立伺服器</li><li><strong>2013-2020 年</strong>：持續營運與升級</li><li><strong>2020 年</strong>：因經費問題短暫關服</li><li><strong>2020 年</strong>：使用獎學金升級光纖網路，重新開服</li><li><strong>2020-至今</strong>：持續營運，支援 1.12.2 與 1.19.4 版本</li></ul><h3 id="伺服器教學與功能" tabindex="-1">伺服器教學與功能 <a class="header-anchor" href="#伺服器教學與功能" aria-label="Permalink to “伺服器教學與功能”">​</a></h3><p>伺服器網站提供豐富的教學與社群資源：</p><ul><li><strong>伺服器教學</strong>：優質玩家驗證、破壞查詢、住宅區合地</li><li><strong>規則說明</strong>：完整的伺服器規則與守則</li><li><strong>指令教學</strong>：公會指令、結婚指令、領地指令</li><li><strong>宣傳資源</strong>：伺服器宣傳圖片與影片展示</li></ul><hr><h2 id="android-應用程式" tabindex="-1">Android 應用程式 <a class="header-anchor" href="#android-應用程式" aria-label="Permalink to “Android 應用程式”">​</a></h2><h3 id="google-play-開發者" tabindex="-1">Google Play 開發者 <a class="header-anchor" href="#google-play-開發者" aria-label="Permalink to “Google Play 開發者”">​</a></h3><p>在 Google Play 平台上以 <strong>Dongdong</strong> 的名義發佈多款應用程式，總下載量超過 50+ 次。</p><h3 id="已發佈的應用程式" tabindex="-1">已發佈的應用程式 <a class="header-anchor" href="#已發佈的應用程式" aria-label="Permalink to “已發佈的應用程式”">​</a></h3><table tabindex="0"><thead><tr><th>應用程式名稱</th><th>類型</th><th>說明</th></tr></thead><tbody><tr><td><strong>東東伺服器遊戲</strong></td><td>休閒掛機遊戲</td><td>提供玩家支援伺服器與獲得福利的遊戲玩法</td></tr><tr><td><strong>東東的 OOXX 遊戲</strong></td><td>小遊戲</td><td>輕鬆有趣的小遊戲</td></tr><tr><td><strong>看誰比較快</strong></td><td>競速遊戲</td><td>速度競賽遊戲</td></tr></tbody></table><h3 id="技術細節" tabindex="-1">技術細節 <a class="header-anchor" href="#技術細節" aria-label="Permalink to “技術細節”">​</a></h3><ul><li><strong>開發平台</strong>：Android (Java/Kotlin)</li><li><strong>發佈平台</strong>：Google Play Store</li><li><strong>總下載量</strong>：50+ 次</li></ul><hr><h2 id="畢業微電影" tabindex="-1">畢業微電影 <a class="header-anchor" href="#畢業微電影" aria-label="Permalink to “畢業微電影”">​</a></h2><h3 id="大道國中畢業微電影" tabindex="-1">大道國中畢業微電影 <a class="header-anchor" href="#大道國中畢業微電影" aria-label="Permalink to “大道國中畢業微電影”">​</a></h3><p>在國中時期（2015-2016 年），與學校國文老師 <a href="https://www.facebook.com/dadulucy" target="_blank" rel="noreferrer">鄭麗美</a> 合作，為大道國中畢業生製作畢業微電影。</p><h3 id="作品列表" tabindex="-1">作品列表 <a class="header-anchor" href="#作品列表" aria-label="Permalink to “作品列表”">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>作品名稱</th><th>連結</th><th>觀看次數</th></tr></thead><tbody><tr><td><strong>2015</strong></td><td>2015 畢業微電影</td><td><a href="https://www.youtube.com/watch?v=df7rQDfLSqU" target="_blank" rel="noreferrer">YouTube</a></td><td>3,600+</td></tr><tr><td><strong>2016</strong></td><td>2016 畢業微電影</td><td><a href="https://www.youtube.com/watch?v=cpNNkTnlw68" target="_blank" rel="noreferrer">YouTube</a></td><td>3,000+</td></tr></tbody></table><h3 id="專案意義" tabindex="-1">專案意義 <a class="header-anchor" href="#專案意義" aria-label="Permalink to “專案意義”">​</a></h3><p>這些微電影不僅是畢業紀念，更是吳彥東早期影音創作的起點。透過與老師的合作，學習了影片剪輯、腳本撰寫、拍攝技巧等技能，也為日後的 YouTube 創作奠定了基礎。</p><hr><h2 id="開源貢獻" tabindex="-1">開源貢獻 <a class="header-anchor" href="#開源貢獻" aria-label="Permalink to “開源貢獻”">​</a></h2><h3 id="npm-套件維護" tabindex="-1">NPM 套件維護 <a class="header-anchor" href="#npm-套件維護" aria-label="Permalink to “NPM 套件維護”">​</a></h3><p>積極參與開源社群，維護多個 NPM 套件：</p><ul><li><strong>vite-plugin-vue-layouts</strong>：Vue.js 佈局插件</li><li><strong>secure-ls</strong>：加密本地儲存工具</li></ul><h3 id="github-開發" tabindex="-1">GitHub 開發 <a class="header-anchor" href="#github-開發" aria-label="Permalink to “GitHub 開發”">​</a></h3><p>在 GitHub 上積極開發與維護多個專案，包括：</p><ul><li>個人部落格網站 (<a href="https://wuc656.github.io" target="_blank" rel="noreferrer">wuc656.github.io</a>)</li><li>Minecraft 伺服器相關工具</li><li>各種程式設計練習與專案</li></ul><hr><h2 id="youtube-頻道" tabindex="-1">YouTube 頻道 <a class="header-anchor" href="#youtube-頻道" aria-label="Permalink to “YouTube 頻道”">​</a></h2><h3 id="wuc656" tabindex="-1">@wuc656 <a class="header-anchor" href="#wuc656" aria-label="Permalink to “@wuc656”">​</a></h3><p>YouTube 頻道已運營超過 10 年，擁有 215+ 訂閱者與 1400+ 部影片。</p><h3 id="內容類型" tabindex="-1">內容類型 <a class="header-anchor" href="#內容類型" aria-label="Permalink to “內容類型”">​</a></h3><ul><li><strong>Minecraft 伺服器影片</strong>：伺服器介紹、遊戲實況</li><li><strong>畢業微電影</strong>：大道國中 2015、2016 畢業紀念</li><li><strong>遊戲實況</strong>：英雄聯盟、WePlay 狼人殺等</li><li><strong>技術分享</strong>：電腦相關知識</li></ul><h3 id="代表影片" tabindex="-1">代表影片 <a class="header-anchor" href="#代表影片" aria-label="Permalink to “代表影片”">​</a></h3><table tabindex="0"><thead><tr><th>影片名稱</th><th>觀看次數</th></tr></thead><tbody><tr><td>東東的創世神 1.5.2 伺服器介紹</td><td>6,200+</td></tr><tr><td>大道國中 45 屆畢業微電影</td><td>3,600+</td></tr><tr><td>大道國中 46 屆畢業微電影</td><td>3,000+</td></tr></tbody></table><h3 id="連結" tabindex="-1">連結 <a class="header-anchor" href="#連結" aria-label="Permalink to “連結”">​</a></h3><ul><li><strong>YouTube 頻道</strong>：<a href="https://www.youtube.com/@wuc656" target="_blank" rel="noreferrer">@wuc656</a></li><li><strong>播放清單</strong>：<a href="https://www.youtube.com/user/wuc656/playlists" target="_blank" rel="noreferrer">YouTube 播放清單</a></li></ul><hr><h2 id="twitch-直播" tabindex="-1">Twitch 直播 <a class="header-anchor" href="#twitch-直播" aria-label="Permalink to “Twitch 直播”">​</a></h2><p>曾在 Twitch 上進行遊戲直播，內容包含 Minecraft 遊戲實況等。</p><ul><li><strong>Twitch 個人檔案</strong>：<a href="https://www.twitch.tv/wuc656/profile" target="_blank" rel="noreferrer">wuc656</a></li></ul><hr><h2 id="個人部落格與社群" tabindex="-1">個人部落格與社群 <a class="header-anchor" href="#個人部落格與社群" aria-label="Permalink to “個人部落格與社群”">​</a></h2><ul><li><strong>個人部落格</strong>：<a href="https://www.wuc656.com/" target="_blank" rel="noreferrer">wuc656.com</a></li><li><strong>GitHub Pages</strong>：<a href="https://wuc656.github.io" target="_blank" rel="noreferrer">wuc656.github.io</a></li></ul>',56)])])}const u=r(o,[["render",n]]);export{b as __pageData,u as default};
